class Solution {
public:
    int possibleStringCount(string word, int k) {
        int n = word.size();
        int mod = 1e9 + 7;
        vector<int> cnt(26);
        for (char c : word) {
            cnt[c - 'a']++;
        }
        int max_len = 0;
        for (int i = 0; i < 26; i++) {
            max_len = max(max_len, cnt[i]);
        }
        int res = 1;
        for (int i = 0; i < max_len; i++) {
            long long ways = 1;
            for (int j = 0; j < 26; j++) {
                ways = ways * (cnt[j] - i) % mod;
            }
            res = (res + ways) % mod;
        }
        return res;
    }
};
